const data = $json;

// -----------------------------
// 1️⃣ EXPERIENCE PARSING
// -----------------------------
let expMin = null;
let expMax = null;

if (data["Experience"]) {
  const expText = data["Experience"].toString();

  const rangeMatch = expText.match(/(\d+)\s*to\s*(\d+)/i);
  const singleMatch = expText.match(/(\d+)/);

  if (rangeMatch) {
    expMin = parseInt(rangeMatch[1]);
    expMax = parseInt(rangeMatch[2]);
  } else if (singleMatch) {
    expMin = parseInt(singleMatch[1]);
    expMax = expMin;
  }
}

// -----------------------------
// 2️⃣ SALARY PARSING
// Handles:
// "$59K-$99K"
// "$50,000 - $80,000"
// "50000-80000"
// -----------------------------
let salaryMin = null;
let salaryMax = null;

if (data["Salary Range"]) {
  const salaryText = data["Salary Range"].toString();

  const kMatch = salaryText.match(/\$?(\d+)K\s*-\s*\$?(\d+)K/i);
  const numberMatch = salaryText.match(/(\d[\d,]*)\s*-\s*(\d[\d,]*)/);

  if (kMatch) {
    salaryMin = parseInt(kMatch[1]) * 1000;
    salaryMax = parseInt(kMatch[2]) * 1000;
  } else if (numberMatch) {
    salaryMin = parseInt(numberMatch[1].replace(/,/g, ""));
    salaryMax = parseInt(numberMatch[2].replace(/,/g, ""));
  }
}

// -----------------------------
// 3️⃣ BENEFITS CLEANING
// -----------------------------
let benefits = [];

if (data["Benefits"]) {
  benefits = data["Benefits"]
    .replace(/[{}']/g, "")
    .split(",")
    .map(b => b.trim())
    .filter(b => b.length > 2);
}

// -----------------------------
// 4️⃣ SKILLS CLEANING (IMPROVED)
// Handles broken parentheses + long sentences
// -----------------------------
let skills = [];

if (data["skills"]) {
  const rawSkills = data["skills"]
    .replace(/\(.*?\)/g, "")       // remove parentheses content
    .replace(/\./g, ",")           // treat periods as separators
    .replace(/\s{2,}/g, ",");      // break large spaces

  skills = rawSkills
    .split(",")
    .map(s => s.trim())
    .filter(s => s.length > 2);
}

// -----------------------------
// 5️⃣ COMPANY PROFILE PARSING
// -----------------------------
let companyProfile = {};
try {
  companyProfile = JSON.parse(data["Company Profile"]);
} catch (e) {
  companyProfile = {};
}

// -----------------------------
// 6️⃣ LOCATION NORMALIZATION
// -----------------------------
const city = data["location"] || "";
const country = data["Country"] || "";
const fullLocation = `${city}${city && country ? ", " : ""}${country}`;

// -----------------------------
// 7️⃣ WORK TYPE NORMALIZATION
// -----------------------------
let workType = data["Work Type"] || "";
workType = workType.toString().toLowerCase();

// -----------------------------
// 8️⃣ CLEAN OBJECT (FINAL)
// -----------------------------
const cleanedJob = {
  job_id: data["Job Id"],
  title: data["Job Title"],
  role: data["Role"],
  role_category: data["Role"] || "",
  company: data["Company"],
  city: city,
  country: country,
  location: fullLocation,
  work_type: workType,
  experience_min: expMin,
  experience_max: expMax,
  salary_min: salaryMin,
  salary_max: salaryMax,
  qualifications: data["Qualifications"] || "",
  description: data["Job Description"] || "",
  responsibilities: data["Responsibilities"] || "",
  benefits: benefits,
  skills: skills,
  industry: companyProfile.Industry || "",
  sector: companyProfile.Sector || ""
};

// -----------------------------
// 9️⃣ RETURN CLEANED OBJECT
// -----------------------------
return [{ json: cleanedJob }];

const job = $json;

const text = `
JOB TITLE: ${job.title}
ROLE: ${job.role}
COMPANY: ${job.company}
LOCATION: ${job.location}
WORK TYPE: ${job.work_type}
EXPERIENCE REQUIRED: ${job.experience_min}-${job.experience_max} years
SALARY RANGE: ${job.salary_min}-${job.salary_max}

QUALIFICATIONS:
${job.qualifications}

DESCRIPTION:
${job.description}

RESPONSIBILITIES:
${job.responsibilities}

SKILLS:
${job.skills.join(", ")}

BENEFITS:
${job.benefits.join(", ")}

INDUSTRY:
${job.industry}

SECTOR:
${job.sector}
`;

return [
  {
    json: {
      text: text.trim()
    }
  }
];
